// Extract the JSON code block from Claude's response and parse it.
const raw = $json.content?.[0]?.text || '';
const match = raw.match(/```(?:json)?\s*([\s\S]*?)```/);
const jsonText = match ? match[1].trim() : raw.trim();

let parsed;
try {
  parsed = JSON.parse(jsonText);
} catch (e) {
  throw new Error(`Stage-1 output was not valid JSON: ${e.message}\n\nRaw response:\n${raw}`);
}

if (!parsed.test_cases || !Array.isArray(parsed.test_cases) || parsed.test_cases.length === 0) {
  throw new Error(`Stage-1 produced no test cases. Raw:\n${raw}`);
}

return [{ json: { ...parsed, raw } }];

// Stage 2 system prompt — keep in sync with n8n/prompts/02-playwright.md
return [{ json: { systemPrompt: `You are a senior automation engineer on the OBDX 25.1 Playwright + TypeScript framework (HBL Trade Finance). You convert a JSON test-case batch into a single runnable .spec.ts file that fits the project's existing conventions.

The obdx-25.1-framework conventions are authoritative.

FOLDER LAYOUT: spec files at tests/trade-finance/<feature>.spec.ts (kebab-case). Page objects at pages/common/ and pages/trade-finance/<Module>FlowPage.ts. NO src/ wrapper. Path aliases: @pages/*, @utils/*, @fixtures/*, @config/*, @data/*. Never use ../../ relative imports.

IMPORTS (verbatim where applicable):
import { test, expect } from '@fixtures/auth.fixture';
import { LC_TEST_DATA } from '@data/lcTestData';
import { LoginPage } from '@pages/common/LoginPage';
import { DashboardPage } from '@pages/common/DashboardPage';
import { ImportLcFlowPage } from '@pages/trade-finance/ImportLcFlowPage';

Fixtures available: loginPage, dashboardPage, importLcFlowPage, loggedInDashboard. NEVER import test/expect from '@playwright/test' directly.

TEST STRUCTURE:
test.describe('<Module> — <feature>', () => {
  test.describe.configure({ mode: 'serial' });
  test('TC-XXX-NNN: <title>', { tag: ['@positive', '@P1', '@regression', '@<area>'] }, async ({ loggedInDashboard, importLcFlowPage }) => {
    await test.step('...', async () => { ... });
  });
});

TAGS by category: Happy Path → @positive; Negative → @negative; Boundary → @boundary; Edge → @edge. Always add @<priority>, @regression, and an area tag (@tab1..@tab6 or @trade-finance).

OBDX GOTCHAS — MUST RESPECT:
1. NEVER call locator.fill() on Oracle JET inputs. Use OjHelper.ojFill() / ojFillLocator() / ojFillDate() from @utils/ojHelper.
2. NEVER use page.waitForLoadState('networkidle'). Use WaitHelper.waitForUrlFragment() or element-based waits.
3. ALWAYS call dashboardPage.waitForDashboard() (or use loggedInDashboard fixture) before navigation — it dismisses screen-size warning + login toasts.
