- submitFromAttachments, assertOnReviewPage, submitFromReview, assertOnConfirmationPage, assertConfirmation, getReferenceNumber
- Assertions: assertApplicantAddressReadOnly, assertApplicantCountryReadOnly, assertBeneficiaryAddressReadOnly, assertBeneficiaryCountryReadOnly, assertSwiftBankAutoFilled, assertTotalExposureContains, assertNextBlockedWithError, clickNext

If a Stage-1 step needs a method not in this list, ADD a // FIXME: comment in the spec and call clickNext / a placeholder — do NOT invent locators or page methods.

OUTPUT FORMAT — STRICT: return ONLY a single fenced TypeScript code block. No prose before or after. The block is the complete contents of tests/trade-finance/${$('Set Config').item.json.featureSlug}.spec.ts.

Feature slug: ${$('Set Config').item.json.featureSlug}
Module code: ${$('Set Config').item.json.moduleCode}` } }];

// Strip the fenced code block from Claude's response.
const raw = $json.content?.[0]?.text || '';
const match = raw.match(/```(?:ts|typescript)?\s*([\s\S]*?)```/);
const code = match ? match[1].trim() : raw.trim();

if (!code.includes("from '@fixtures/auth.fixture'") && !code.includes('from "@fixtures/auth.fixture"')) {
  throw new Error(`Stage-2 output missing the @fixtures/auth.fixture import. Raw:\n${raw}`);
}

const slug = $('Set Config').item.json.featureSlug;
const projectPath = $('Set Config').item.json.projectPath;
const specPath = `${projectPath}/tests/trade-finance/${slug}.spec.ts`;

return [{ json: { code, specPath, slug, projectPath, raw } }];

// readWriteFile expects a binary buffer on `data`. Convert the spec text → buffer first.
const code = $('Extract Spec').item.json.code;
const buffer = Buffer.from(code, 'utf8');
return [{
  json: $('Extract Spec').item.json,
  binary: { data: { data: buffer.toString('base64'), mimeType: 'text/typescript', fileName: `${$('Extract Spec').item.json.slug}.spec.ts` } }
}];

// Read playwright-report/results.json and summarise.
const fs = require('fs');
const path = require('path');
const projectPath = $('Set Config').item.json.projectPath;
const resultsPath = path.join(projectPath, 'playwright-report', 'results.json');

let summary = {
  status: 'unknown',
  passed: 0,
  failed: 0,
  skipped: 0,
  flaky: 0,
  duration_ms: 0,
  failures: [],
};

try {
  const raw = fs.readFileSync(resultsPath, 'utf8');
  const r = JSON.parse(raw);
  summary.duration_ms = r.stats?.duration ?? 0;
  summary.status = (r.stats?.unexpected ?? 0) > 0 ? 'failed' : 'passed';
  // Walk suites recursively to collect tests.
  const walk = (suite) => {
    (suite.suites || []).forEach(walk);
    (suite.specs || []).forEach((spec) => {
      (spec.tests || []).forEach((t) => {
        const result = (t.results || [])[0];
        if (!result) return;
        if (result.status === 'passed') summary.passed++;
        else if (result.status === 'skipped') summary.skipped++;
        else if (result.status === 'flaky') summary.flaky++;
        else {
          summary.failed++;
          summary.failures.push({
            test: spec.title,
            file: spec.file,
            error: result.error?.message?.split('\n').slice(0, 5).join('\n') ?? 'unknown',
          });
        }
      });
    });
  };
  (r.suites || []).forEach(walk);
} catch (e) {
  summary.status = 'no-results';
  summary.error = e.message;
}

return [{ json: { summary, specPath: $('Extract Spec').item.json.specPath, executionStdout: ($('Run Playwright').item.json.stdout || '').slice(-4000) } }];
